# Category: sql_injection

package controllers

import javax.inject._
import play.api.mvc._
import slick.jdbc.JdbcProfile
import slick.jdbc.MySQLProfile.api._

@Singleton
class ProductController @Inject() (dbConfigProvider: DatabaseConfigProvider) extends Controller {
  def search(queryString: String): Action[AnyContent] = Action { implicit request =>
    val dbConfig = dbConfigProvider.get[JdbcProfile]
    val sqlFragment = queryString.split(" ").map(_.toLowerCase()).mkString(" AND ")
    val products = dbConfig.db.run(sql"SELECT * FROM products WHERE ${sqlFragment}".as[Product])
    Ok(products)
  }
}